// পুরাতন পদ্ধতি: Callback
function fetchData(callback) {
  setTimeout(() => {
    callback("ডেটা পাওয়া গেছে");
  }, 1000);
}
fetchData((data) => console.log(data));

function fetchUser() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const success = true;
      if (success) resolve({ name: "জুবায়ের" });
      else reject("এরর হয়েছে!");
    }, 1000);
  });
}

fetchUser()
  .then((user) => console.log("পাওয়া গেছে:", user.name))
  .catch((err) => console.log("সমস্যা:", err));

async function getUser() {
  try {
    const user = await fetchUser();
    console.log("ইউজার:", user.name);
  } catch (err) {
    console.log("সমস্যা:", err);
  }
}
getUser();

// Fetch API দিয়ে রিয়েল উদাহরণ
async function getPosts() {
  const response = await fetch("https://api.example.com/posts");
  const data = await response.json();
  console.log(data);
